import numpy as np

def mean(x):
    x = np.asarray(x, dtype=float)
    return float(np.sum(x) / len(x))


def variance(x, ddof=1):
    x = np.asarray(x, dtype=float)
    n = len(x)
    if n <= ddof:
        raise ValueError(f"Need more than {ddof} samples, got {n}")
    mu = np.sum(x) / n
    return float(np.sum((x - mu) ** 2) / (n - ddof))


def std(x, ddof=1):
    return float(np.sqrt(variance(x, ddof)))

